SELECT DISTINCT ?catalog ?title ?homepage ?description
WHERE {
  ?catalog a dcat:Catalog .
  ?catalog dct:spatial ?spatial .
  FILTER(CONTAINS(STR(?spatial), "EL") || CONTAINS(STR(?spatial), "greece") || CONTAINS(STR(?spatial), "GRC"))
