}

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX schema: <http://schema.org/>

SELECT ?catalog ?datasetCount ?modified ?publisher
WHERE {
  VALUES ?catalog { 
    <http://data.europa.eu/88u/catalogue/ypes>
    <http://data.europa.eu/88u/catalogue/data-gov-gr>
  }
  OPTIONAL {
    SELECT ?catalog (COUNT(DISTINCT ?dataset) AS ?datasetCount)
    WHERE { ?catalog dcat:dataset ?dataset }
    GROUP BY ?catalog
  }
  OPTIONAL { ?catalog dcterms:modified ?modified }
  OPTIONAL { ?catalog dcterms:publisher ?publisherNode . ?publisherNode schema:name ?publisher }
}

