SELECT ?dataset ?title ?issued ?modified ?format
WHERE {
  ?dataset dcat:catalog <http://data.europa.eu/88u/catalogue/data-gov-gr> ;
           dcterms:title ?title .
  OPTIONAL { ?dataset dcterms:issued ?issued }
  OPTIONAL { ?dataset dcterms:modified ?modified }
  FILTER(LANG(?title) = "en" || LANG(?title) = "")
}
ORDER BY DESC(?modified)
LIMIT 15

