} LIMIT 5

PREFIX bathw: <https://w3id.org/italia/env/onto/bathw/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX geo: <http://www.w3.org/2003/01/geo/wgs84_pos#>

SELECT ?stazione ?nome ?lat ?long ?anno ?qualita
WHERE {
  ?stazione a bathw:BathingWater ;
            rdfs:label ?nome .
  OPTIONAL { ?stazione geo:lat ?lat }
  OPTIONAL { ?stazione geo:long ?long }
  ?obs bathw:refersTo ?stazione ;
       bathw:year ?anno ;
       bathw:qualityStatus ?qualita .
}
ORDER BY ?anno ?nome

SELECT DISTINCT ?type (COUNT(?s) AS ?count)
WHERE {
  GRAPH <https://w3id.org/italia/env/ld/bathw> {
    ?s a ?type .
  }
}
GROUP BY ?type
ORDER BY DESC(?count)

SELECT DISTINCT ?p (COUNT(?s) AS ?count)
WHERE {
  GRAPH <https://w3id.org/italia/env/ld/bathw/2024/> {
    ?s ?p ?o .
  }
}
GROUP BY ?p
ORDER BY DESC(?count)

PREFIX top: <https://w3id.org/italia/env/onto/top/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?obs ?label ?id ?qualita ?anno
WHERE {
  GRAPH <https://w3id.org/italia/env/ld/bathw/2024/> {
    ?obs top:identifier ?id ;
         rdfs:label ?label ;
         top:isClassifiedBy ?qualita ;
         top:atTime ?anno .
  }
}
